public void create(int row)
{
    LedgerJournalTable ledgerJournalTable;
    LedgerJournalTrans ledgerJournalTrans;
    LedgerJournalName ledgerJournalName;

    VendTable vendTable;
    CustTable custTable;
    DimensionDynamicAccount ledgerDim, offsetLedgerDim;
    Voucher voucher;
    DimensionDisplayValue offsetValue;
    str journalNumber;

    DimensionDynamicAccount ledgerDimension, ledgerDimensionOrg;
    LedgerJournalEngine ledgerJournalEngine;

    journalNumber = range.get_Item(row, 1).Value;

    //select * from ledgerJournalTable
    //  where ledgerJournalTable.JournalNum == journalNumber;

    container cont = [range.get_Item(row, 11).Value, range.get_Item(row, 12).Value, range.get_Item(row, 13).Value];

    if(journalNumber)
    {
        str docDateStr, transDateStr, dueDateStr, accountType, offsetAccountType;
        int docDateInt, dueDateInt, transDateInt;
        date docDate, dueDate, tansDate;
        CustVendPaymStatus paymStatus;
        Description itemWithHoldingTaxGroup;
        TaxWithholdItemGroupHeading_TH taxWithholdItemGroupHeading_TH;
        HcmPersonnelNumberId approverName;
        Etg_LoaderStaging_Y002 loaderStaging;

        transDateStr = range.get_Item(row, 2).Text.ToString();
        dueDateStr = range.get_Item(row, 14).Text.ToString();

        tansDate = str2Date(transDateStr, 213);
        dueDate = str2Date(dueDateStr, 213);

        LedgerJournalACType ledgerJournalACType, offsetledgerJournalACType;

        // select * from ledgerJournalName where ledgerJournalName.JournalName == ledgerJournalTable.JournalName;

        // voucher = new JournalVoucherNum(JournalTableData::newTable(ledgerJournalTable)).getNew(true);
        loaderStaging = null;
        //  loaderStaging = ledgerJournalTable.DataAreaId;
        loaderStaging.JournalNum = journalNumber;

        loaderStaging.AccountType = LedgerJournalACType::Ledger;
        // ledgerDim = LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber(range.get_Item(row, 4).Value, LedgerJournalACType::Ledger);
        ledgerDimensionOrg = this.offsetLedgerDimensionValue(range.get_Item(row, 3).Value, cont);
        loaderStaging.LedgerDimension = ledgerDimensionOrg;
        loaderStaging.DefaultDimension = this.createDefaultDimension(range.get_Item(row, 4).Value, range.get_Item(row, 5).Value, range.get_Item(row, 6).Value);
        loaderStaging.OffsetDefaultDimension = this.createDefaultDimension(range.get_Item(row, 4).Value, range.get_Item(row, 5).Value, range.get_Item(row, 6).Value);

        loaderStaging.Txt =  range.get_Item(row, 7).Value;
        loaderStaging.AmountCurDebit = range.get_Item(row, 8).Value;
        loaderStaging.AmountCurCredit = range.get_Item(row, 9).Value;
        loaderStaging.CurrencyCode = "USD";
        loaderStaging.TransDate = tansDate;
       // loaderStaging.ExchRate = any2Real(range.get_Item(row, 10).Value) * 100;

        DimensionAttributeValueCombination dimAttrValComb;

        loaderStaging.OffsetAccountType = LedgerJournalACType::Ledger;
        if(range.get_Item(row, 10).Value)
        {
            ledgerDimension = this.offsetLedgerDimensionValue(range.get_Item(row, 10).Value, cont);
        }
        else
        {
            offsetLedgerDim = str2Int64("");
        }
        loaderStaging.OffsetLedgerDimension = ledgerDimension;

        loaderStaging.Payment =  range.get_Item(row, 15).Value;
        loaderStaging.Invoice =  range.get_Item(row, 16).Value;
        loaderStaging.ReverseEntry = NoYes::Yes;
        loaderStaging.ReverseDate = dueDate;
        lineimported++;
        loaderStaging.insert();
    }

}

public DimensionDefault createDefaultDimension(str vertical, str businessUnit,
                                                   str intercompany)
{
    DimensionAttributeValueSetStorage   valueSetStorage = new DimensionAttributeValueSetStorage();
    DimensionDefault                    result;
    int                     i;
    DimensionAttribute      dimensionAttribute;
    DimensionAttributeValue dimensionAttributeValue;

    //Change the dimension names. Use the dimension name which are open and active in the system

    container               conAttr = ["Vertical","BusinessUnit","Intercompany"];

    container               conValue = [vertical, businessUnit, intercompany];

    str                     dimValue;

    for (i = 1; i <= conLen(conAttr); i++)
    {
        dimensionAttribute = dimensionAttribute::findByName(conPeek(conAttr,i));
        if (dimensionAttribute.RecId == 0)
        {
            continue;
        }
        dimValue = conPeek(conValue,i);
        if (dimValue != "")
        {
            dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,dimValue,false,true);
            valueSetStorage.addItem(dimensionAttributeValue);
        }
    }

    result = valueSetStorage.save();
    //It reutrns the value of type DimensionDefault
    return result;
}

/// <summary>
///
/// </summary>
/// <param name = "_mainAccountId"></param>
/// <param name = "_conData"></param>
/// <returns></returns>
public DimensionDynamicAccount offsetLedgerDimensionValue(MainAccountNum _mainAccountId, container _conData)
{
    #define.Vertical('VERTICALVALUE')
    #define.BusinessUnit('BUSINESSUNITVALUE')
    #define.InterCompany('INTERCOMPANYVALUE')

    RecId dimAttId_MainAccount;
    MainAccount mainAccount;

    DimensionAttribute dimensionAttribute;
    DimensionAttributeValue dimensionAttributeValue;
    DimensionSetSegmentName DimensionSet;
    DimensionStorage dimStorage;

    LedgerAccountContract ledgerAccountContract = new LedgerAccountContract();
    DimensionAttributeValueContract valueContract;

    List valueContracts = new List(Types::Class);

    DimensionAttributeValueCombination dimensionAttributeValueCombination;

    mainAccount = MainAccount::findByMainAccountId(_mainAccountId);

    while select DimensionValueColumnName from dimensionAttribute
        where dimensionAttribute.DimensionValueColumnName == #Vertical
        || dimensionAttribute.DimensionValueColumnName == #BusinessUnit
        || dimensionAttribute.DimensionValueColumnName == #InterCompany
    {
        switch(dimensionAttribute.DimensionValueColumnName)
        {
            case #Vertical:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,1));
                break;

            case #BusinessUnit:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,2));
                break;

            case #InterCompany:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,3));
                break;

        }

        if(dimensionAttributeValue)
        {
            valueContract = new DimensionAttributeValueContract();
            valueContract.parmName(dimensionAttribute.Name);
            valueContract.parmValue(dimensionAttributeValue.CachedDisplayValue);
            valueContracts.addEnd(valueContract);
        }
    }

    ledgerAccountContract.parmMainAccount(_mainAccountId);
    ledgerAccountContract.parmValues(valueContracts);

    dimStorage = DimensionServiceProvider::buildDimensionStorageForLedgerAccount(ledgerAccountContract);
    dimensionAttributeValueCombination = DimensionAttributeValueCombination::find(dimStorage.save());

    return dimensionAttributeValueCombination.RecId;
}

void import()
{
    Container               con;
    InventTable             inventTable;
    Etg_LoaderStaging_Y002 Etg_LoaderStaginglocal;
    LedgerJournalId journalID
    ;
    setPrefix("Import master data");
    // delete_from Etg_LoaderStaginglocal;
    if (this.openFile())
    {
        using (ExcelPackage Package = new ExcelPackage(stream))
        {
            int                         rowCount, i, endRow, startRow;
            Package.Load(stream);
            ExcelWorksheet  worksheet   = package.get_Workbook().get_Worksheets().get_Item(1);
            range       = worksheet.Cells;
            endRow      = worksheet.Dimension.End.Row;
            startRow    = worksheet.Dimension.Start.Row;
            rowCount    = endRow - startRow + 1;
            // OfficeOpenXml.ExcelRange range1;

            try
            {
                delete_from Etg_LoaderStaginglocal
                    where Etg_LoaderStaginglocal.ETGStatus == NoYes::No
                        && Etg_LoaderStaginglocal.DataAreaId == curExt()
                            && Etg_LoaderStaginglocal.CreatedBy == curUserId();

                for (i = 2; i<= rowCount; i++)
                {
                    setPrefix(strFmt("Line %1", i));
                    this.create(i);

                }
            }
            catch
            {
                throw error("Error - Import template");
            }
        }
    }
    //  select firstonly Etg_LoaderStaginglocal;

    // this.createJournal(Etg_LoaderStaginglocal);
    info(strfmt("%1 record(s) imported", lineimported));
}

boolean openFile()
{
    boolean ret = false;

    if (fileUploadResult != null && fileUploadResult.getUploadStatus())
    {
        stream = fileUploadResult.openResult();
        ret = true;
    }
    else
    {
        throw error(strfmt("@SYS62207",filename));
    }

    return ret;
}

public Object dialog()
{
    dialog = super();

    DialogGroup dialogGroup = dialog.addGroup('Upload file');

    FormBuildControl formBuildControl = dialog.formBuildDesign().control(dialogGroup.name());
    dialogFileUpload = formBuildControl.addControlEx(classstr(FileUpload), 'FileUpload');
    dialogFileUpload.style(FileUploadStyle::MinimalWithFilename);
    dialogFileUpload.fileNameLabel("@SYS308842");
    dialogFileUpload.fileTypesAccepted(".xlsx");

    return dialog;
}

/// <summary>
/// Disables the dialog Ok button until the file upload is complete.
/// </summary>
/// <param name="_dialog">The <c>Runbase</c> dialog object.</param>
public void dialogPostRun(DialogRunbase _dialog)
{
    fileUpload = _dialog.formRun().control(_dialog.formRun().controlId('FileUpload'));
    fileUpload.notifyUploadCompleted += eventhandler(this.uploadCompleted);
    this.setDialogOkButtonEnabled(_dialog, false);
}

/// <summary>
/// After the file has been uploaded, the Ok button is enabled.
/// </summary>
public void uploadCompleted()
{
    filename = fileUpload.fileName();

    this.setDialogOkButtonEnabled(dialog, true);

    fileUploadResult = fileUpload.getFileUploadResult();

    fileUpload.notifyUploadCompleted -= eventhandler(this.UploadCompleted);
}

/// <summary>
/// Enables or disables the dialog Ok button.
/// </summary>
/// <param name = "_dialog">The <c>Runbase</c> dialog object.</param>
/// <param name = "_isEnabled">Indicates to enable or disable the Ok button.</param>
protected void setDialogOkButtonEnabled(DialogRunbase _dialog, boolean _isEnabled)
{
    FormControl okButtonControl = _dialog.formRun().control(_dialog.formRun().controlId('OkButton'));

    if (okButtonControl)
    {
        okButtonControl.enabled(_isEnabled);
    }
}

public boolean unpack(container packedClass)
{
    Version version = runbase::getVersion(packedClass);
    ;
    switch (version)
    {
        case #CurrentVersion:
            [version,#CurrentList] = packedClass;
            break;
        default:
            return false;
    }
    return true;
}

static void main(Args _args)
{
    ETGGeneralJournalImport_Y002   import;
    FormRun formRun;
    Args    args;
    ;
    import = new ETGGeneralJournalImport_Y002();
    if (import.prompt())
    {
        import.run();
    }
}

